class CacheManager:
    """Centralized cache management with statistics tracking."""
    
    def __init__(self, client):
        self.client = client
        self.stats = {'hits': 0, 'misses': 0, 'errors': 0, 'sets': 0, 'deletes': 0}
    
    def get(self, key):
        """Get a value from cache."""
        try:
            result = self.client.get(key)
            if result is not None:
                self.stats['hits'] += 1
            else:
                self.stats['misses'] += 1
            return result
        except Exception as e:
            self.stats['errors'] += 1
            app.logger.error(f"Cache GET error for key '{key}': {e}")
            return None
    
    def set(self, key, value, ttl=None):
        """Set a value in cache with optional TTL."""
        try:
            ttl = ttl or app.config['DEFAULT_CACHE_TTL']
            self.client.set(key, value, expire=ttl)
            self.stats['sets'] += 1
            return True
        except Exception as e:
            self.stats['errors'] += 1
            app.logger.error(f"Cache SET error for key '{key}': {e}")
            return False
    
    def delete(self, key):
        """Delete a value from cache."""
        try:
            self.client.delete(key)
            self.stats['deletes'] += 1
            return True
        except Exception as e:
            self.stats['errors'] += 1
            app.logger.error(f"Cache DELETE error for key '{key}': {e}")
            return False
    
    def invalidate_pattern(self, prefix):
        """Invalidate cache entries by prefix (track keys manually)."""
        try:
            tracked_keys = self.get(f"_tracked_keys_{prefix}") or []
            for key in tracked_keys:
                self.delete(key)
            self.delete(f"_tracked_keys_{prefix}")
            return True
        except Exception as e:
            self.stats['errors'] += 1
            app.logger.error(f"Cache invalidation error for prefix '{prefix}': {e}")
            return False
    
    def track_key(self, prefix, key):
        """Track a cache key under a prefix for later invalidation."""
        try:
            tracked_keys = self.get(f"_tracked_keys_{prefix}") or []
            if key not in tracked_keys:
                tracked_keys.append(key)
                self.set(f"_tracked_keys_{prefix}", tracked_keys, ttl=86400)
        except Exception as e:
            app.logger.error(f"Key tracking error: {e}")
    
    def get_stats(self):
        """Return cache statistics."""
        total = self.stats['hits'] + self.stats['misses']
        hit_rate = (self.stats['hits'] / total * 100) if total > 0 else 0
        return {
            **self.stats,
            'total_requests': total,
            'hit_rate_percent': round(hit_rate, 2)
        }
    
    def flush_all(self):
        """Flush all cache entries."""
        try:
            self.client.flush_all()
            self.stats = {'hits': 0, 'misses': 0, 'errors': 0, 'sets': 0, 'deletes': 0}
            return True
        except Exception as e:
            self.stats['errors'] += 1
            app.logger.error(f"Cache flush error: {e}")
            return False


cache_manager = CacheManager(cache_client)


def cache_response(ttl=None, key_prefix='api'):
    """Decorator to cache API endpoint responses."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            # Build cache key from request details
            cache_key = f"{key_prefix}:{func.__name__}:{generate_cache_key(
                request.path, str(request.args), *args, **kwargs
            )}"
            
            # Try to get from cache
            cached_result = cache_manager.get(cache_key)
            if cached_result is not None:
                cached_result['_cache'] = 'HIT'
                return jsonify(cached_result)
            
            # Execute function and cache result
            result = func(*args, **kwargs)
            
            if isinstance(result, tuple):
                response_data, status_code = result
            else:
                response_data = result
                status_code = 200
            
            # Only cache successful responses
            if status_code == 200:
                cache_ttl = ttl or app.config['API_CACHE_TTL']
                cache_manager.set(cache_key, response_data, ttl=cache_ttl)
                cache_manager.track_key(key_prefix, cache_key)
                response_data['_cache'] = 'MISS'
            
            return jsonify(response_data), status_code
        
        return wrapper
    return decorator


def cached_db_query(table, record_id=None, filters=None, ttl=None):
    """Execute a database query with caching."""
    cache_key = f"db:{table}:{generate_cache_key(record_id, filters)}"
    
    # Try to get from cache
    cached_result = cache_manager.get(cache_key)
    if cached_result is not None:
        return cached_result, True  # data, was_cached
    
    # Execute query
    result = simulate_db_query(table, record_id, filters)
    
    if result is not None:
        cache_ttl = ttl or app.config['DB_CACHE_TTL']
        cache_manager.set(cache_key, result, ttl=cache_ttl)
        cache_manager.track_key(f"db_{table}", cache_key)
    
    return result, False  # data, was_cached


def cached_api_call(endpoint, ttl=None):
    """Make an external API call with caching."""
    cache_key = f"ext_api:{endpoint}"
    
    # Try to get from cache
    cached_result = cache_manager.get(cache_key)
    if cached_result is not None:
        return cached_result, True
    
    # Make API call
    result = simulate_external_api_call(endpoint)
    
    if result and 'error' not in result:
        cache_ttl = ttl or app.config['API_CACHE_TTL']
        cache_manager.set(cache_key, result, ttl=cache_ttl)
        cache_manager.track_key('ext_api', cache_key)
    
    return result, False


