@app.route('/benchmark', methods=['GET'])
def benchmark():
    """Run a cache performance benchmark."""
    results = {
        'uncached_queries': [],
        'cached_queries': [],
        'summary': {}
    }
    
    # Flush cache first
    cache_manager.flush_all()
    
    # Uncached queries
    uncached_total = 0
    test_queries = [
        ('users', None, None),
        ('users', '1', None),
        ('products', None, None),
        ('products', None, {'category': 'electronics'}),
        ('orders', None, None),
    ]
    
    for table, record_id, filters in test_queries:
        start = time.time()
        cached_db_query(table, record_id=record_id, filters=filters)
        elapsed = time.time() - start
        uncached_total += elapsed
        results['uncached_queries'].append({
            'query': f'{table}(id={record_id}, filters={filters})',
            'time_ms': round(elapsed * 1000, 2),
            'cached': False
        })
    
    # Cached queries (same queries again)
    cached_total = 0
    for table, record_id, filters in test_queries:
        start = time.time()
        cached_db_query(table, record_id=record_id, filters=filters)
        elapsed = time.time() - start
        cached_total += elapsed
        results['cached_queries'].append({
            'query': f'{table}(id={record_id}, filters={filters})',
            'time_ms': round(elapsed * 1000, 2),
            'cached': True
        })
    
    # External API benchmark
    ext_api_uncached = 0
    ext_api_cached = 0
    
    for endpoint in ['weather', 'exchange_rates', 'news', 'stock_prices']:
        start = time.time()
        cached_api_call(endpoint)
        ext_api_uncached += time.time() - start
        
        start = time.time()
        cached_api_call(endpoint)
        ext_api_cached += time.time() - start
    
    speedup_db = (uncached_total / cached_total) if cached_total > 0 else float('inf')
    speedup_api = (ext_api_uncached / ext_api_cached) if ext_api_cached > 0 else float('inf')
    
    results['summary'] = {
        'db_queries': {
            'uncached_total_ms': round(uncached_total * 1000, 2),
            'cached_total_ms': round(cached_total * 1000, 2),
            'speedup': f'{speedup_db:.1f}x'
        },
        'api_calls': {
            'uncached_total_ms': round(ext_api_uncached * 1000, 2),
            'cached_total_ms': round(ext_api_cached * 1000, 2),
            'speedup': f'{speedup_api:.1f}x'
        },
        'cache_stats': cache_manager.get_stats()
    }
    
    return jsonify(results)


